// ============================================================
// パッキング（グリーディー、長い順）
// ============================================================
function pack(pieces, eff, blade) {
  var cnt = {};
  pieces.forEach(function(p){ cnt[p] = (cnt[p]||0)+1; });
  var lengths = Object.keys(cnt).map(Number).sort(function(a,b){return b-a;});

  var allPats = [];
  function enumPats(idx, remSpace, counts, hasAny) {
    if (idx === lengths.length) {
      if (hasAny) allPats.push({ counts: counts.slice(), loss: remSpace });
      return;
    }
    var len = lengths[idx];
    for (var n = 0; n <= cnt[len]; n++) {
      var addSpace = n === 0 ? 0
        : (hasAny || counts.slice(0,idx).some(function(c){return c>0;}) ? blade : 0)
          + len + (n-1)*(len+blade);
      if (n > 0 && addSpace > remSpace) break;
      counts[idx] = n;
      enumPats(idx+1, remSpace - addSpace, counts, hasAny || n>0);
    }
    counts[idx] = 0;
  }
  enumPats(0, eff, new Array(lengths.length).fill(0), false);

  allPats.sort(function(a,b){
    var sa = a.counts.reduce(function(s,n){return s+n;},0);
    var sb = b.counts.reduce(function(s,n){return s+n;},0);
    return sb - sa || a.loss - b.loss;
  });

  var remaining = {};
  lengths.forEach(function(l){ remaining[l] = cnt[l]; });
  var bars = [];

  for (var iter = 0; iter < 500; iter++) {
    var anyLeft = lengths.some(function(l){ return (remaining[l]||0)>0; });
    if (!anyLeft) break;

    var bestPat = null, bestPrimary = -1, bestSecondary = -1;
    for (var pi = 0; pi < allPats.length; pi++) {
      var p = allPats[pi];
      var ok = lengths.every(function(l,li){ return p.counts[li] <= (remaining[l]||0); });
      if (!ok) continue;
      // 最大部材の消化数を最優先、次に合計本数、次にロス小
      var primary = (remaining[lengths[0]]||0) > 0 ? p.counts[0] : 0;
      var secondary = lengths.reduce(function(s,l,li){ return s+p.counts[li]; }, 0);
      if (primary > bestPrimary ||
         (primary === bestPrimary && secondary > bestSecondary) ||
         (primary === bestPrimary && secondary === bestSecondary && bestPat && p.loss < bestPat.loss)) {
        bestPrimary = primary; bestSecondary = secondary; bestPat = p;
      }
    }
    if (!bestPat || bestSecondary===0) break;

    var pat = [];
    lengths.forEach(function(l,li){
      for (var n=0; n<bestPat.counts[li]; n++) {
        pat.push(l);
        remaining[l]--;
      }
    });
    pat.sort(function(a,b){return b-a;});
    bars.push({ pat: pat, loss: bestPat.loss });
  }

  var leftover = [];
  lengths.forEach(function(l){ for(var i=0;i<(remaining[l]||0);i++) leftover.push(l); });
  leftover.sort(function(a,b){return b-a;});
  while (leftover.length > 0) {
    var rem = eff, pat2 = [], newLeft = [];
    for (var i=0; i<leftover.length; i++) {
      var need = leftover[i] + (pat2.length>0?blade:0);
      if (need<=rem){ rem-=need; pat2.push(leftover[i]); } else { newLeft.push(leftover[i]); }
    }
    bars.push({ pat: pat2, loss: rem });
    leftover = newLeft;
  }

  return bars;
}

// ★ 残材優先パッキング
function packWithRemnants(pieces, remnants, stdStocks, blade, endLoss) {
  // 残材リストを長い順にソート
  var sortedRemnants = remnants.slice().sort(function(a,b){return b-a;});
  var remaining = pieces.slice().sort(function(a,b){return b-a;});
  var allBars = [];

  // 各残材1本に対してDPで最良パターンを1本分だけ取り出す
  sortedRemnants.forEach(function(remLen) {
    if (!remaining.length) return;
    var eff = remLen - endLoss;
    if (eff <= 0) return;

    // dpBestPat: 残材1本に詰められる最良パターンを1本分取得
    var best = dpBestPat(remaining, eff, blade);
    if (!best.pat.length) return;

    // 使った部材をremainingから除去
    best.pat.forEach(function(p) {
      var idx = remaining.indexOf(p);
      if (idx >= 0) remaining.splice(idx, 1);
    });

    allBars.push({ pat: best.pat, loss: best.loss, sl: remLen });
  });

  return { remaining: remaining, remnantBars: allBars };
}

function groupBars(bars) {
  var g = [];
  bars.forEach(function(b) {
    var key = b.pat.join(',') + ':' + b.loss;
    var f = g.find(function(x) { return x.key === key; });
    if (f) f.cnt++; else g.push({ key: key, pat: b.pat, loss: b.loss, cnt: 1 });
  });
  return g;
}

// 評価指標を計算するユーティリティ
function calcMetrics(bars, sl, endLoss, kgm, minValidLen) {
  minValidLen = minValidLen || 500;
  var switchCount = 0, validRemnants = 0, invalidRemnants = 0;
  var patternMap = {};
  var prevLen = null;
  var totalLoss = 0, totalUsable = 0;

  bars.forEach(function(b) {
    totalUsable += (b.sl || sl);  // 各バーの実際の定尺を使用
    totalLoss += b.loss;

    // 切断長さの切替回数
    b.pat.forEach(function(len) {
      if (prevLen !== null && len !== prevLen) switchCount++;
      prevLen = len;
    });

    // 端材評価
    if (b.loss >= minValidLen) validRemnants++;
    else if (b.loss > 0) invalidRemnants++;

    // 同一パターン判定（ユニークキー）
    var key = b.pat.slice().sort(function(a,b){return b-a;}).join(',');
    patternMap[key] = (patternMap[key] || 0) + 1;
  });

  // カット数 = 歩留まり最大プランと同じ計算方式
  // ユニークパターンごとに「セット1回 + そのパターンの部材数」を合算
  // 同じパターンを何本繰り返しても1セット分だけカウント
  var totalCuts = Object.keys(patternMap).reduce(function(acc, key) {
    var patLen = key ? key.split(',').length : 0;
    return acc + 1 + patLen;
  }, 0);

  var samePatternCount = Object.keys(patternMap).reduce(function(mx, k) {
    return Math.max(mx, patternMap[k]);
  }, 0);

  // 歩留まり = 実際に切り出した部材長さ合計 ÷ 定尺長さ合計
  // 刃厚・端部ロス・端材はすべてロス扱い（お金計算ベース）
  var totalPieceLen = 0;
  bars.forEach(function(b) {
    b.pat.forEach(function(p) { totalPieceLen += p; });
  });
  var yieldPct = totalUsable > 0 ? (totalPieceLen / totalUsable) * 100 : 0;
  var lossKg = (totalLoss / 1000) * kgm;
  var barKg = (sl / 1000) * kgm * bars.length;
  var lossRate = 100 - yieldPct;

  // バランススコア（高いほど良い）
  var balanceScore = yieldPct * 0.5
    - totalCuts * 0.2
    - invalidRemnants * 0.2
    - switchCount * 0.1;

  return {
    totalCuts: totalCuts,
    switchCount: switchCount,
    validRemnants: validRemnants,
    invalidRemnants: invalidRemnants,
    samePatternCount: samePatternCount,
    yieldPct: yieldPct,
    lossRate: lossRate,
    lossKg: lossKg,
    barKg: barKg,
    totalLoss: totalLoss,
    balanceScore: balanceScore,
    barCount: bars.length,
    patternMap: patternMap
  };
}

// ── 共通ユーティリティ：部材リストに収まる最短定尺を返す ──
function bestStockForPat(pat, stocks, blade, endLoss) {
  var needed = pat.reduce(function(s,p,i){ return s+p+(i>0?blade:0); }, 0);
  var sorted = stocks.slice().sort(function(a,b){ return a.sl-b.sl; });
  for (var i=0; i<sorted.length; i++) {
    if (sorted[i].sl - endLoss >= needed) return sorted[i];
  }
  return null;
}

// ============================================================
// CSP Engine (Browser-side, mirrors Worker logic)
// ============================================================
function enumAllPatterns(stocks, items, demArr, blade, endLoss) {
  var allPats = [];
  stocks.forEach(function(s) {
    var eff = s.sl - endLoss;
    if (eff <= 0) return;
    function bt(idx, rem, cur) {
      if (cur.length > 0) {
        var piece = cur.reduce(function(a,p){return a+p;},0);
        allPats.push({pat:cur.slice(), sl:s.sl, eff:eff, loss:rem, piece:piece, yld:piece/eff});
      }
      for (var i = idx; i < items.length; i++) {
        var w = items[i] + (cur.length > 0 ? blade : 0);
        if (rem < w) continue;
        var used = 0; for(var k=0;k<cur.length;k++) if(cur[k]===items[i]) used++;
        if (used >= demArr[i]) continue;
        cur.push(items[i]); bt(i, rem - w, cur); cur.pop();
      }
    }
    bt(0, eff, []);
  });
  allPats.sort(function(a,b){return b.yld-a.yld;});
  return allPats;
}

function bnbSolve(demArr, items, allPats, timeLimit) {
  var best = {sol:null, bars:Infinity, piece:0};
  var calls = 0;
  var deadline = Date.now() + (timeLimit || 2000);
  function bnb(rem, chosen, bars) {
    if (Date.now() > deadline) return;
    calls++;
    if (!rem.some(function(r){return r>0;})) {
      var piece = chosen.reduce(function(s,c){return s+c.piece;},0);
      if (bars < best.bars || (bars === best.bars && piece > best.piece)) {
        best.bars = bars; best.piece = piece; best.sol = chosen.slice();
      }
      return;
    }
    if (bars >= best.bars) return;
    var totalRem = rem.reduce(function(s,r,i){return s+r*items[i];},0);
    var maxEff = allPats.length ? allPats[allPats.length-1].eff : 1;
    var lb = Math.ceil(totalRem / Math.max(maxEff, 1));
    if (bars + lb >= best.bars) return;
    var tried = 0;
    for (var pi = 0; pi < allPats.length && tried < 120; pi++) {
      var p = allPats[pi]; var ok = true;
      for (var i = 0; i < items.length; i++) {
        var n = 0; for(var k=0;k<p.pat.length;k++) if(p.pat[k]===items[i]) n++;
        if (n > rem[i]) { ok = false; break; }
      }
      if (!ok) continue;
      tried++;
      var nr = rem.slice();
      for (var i = 0; i < items.length; i++) {
        var n = 0; for(var k=0;k<p.pat.length;k++) if(p.pat[k]===items[i]) n++;
        nr[i] -= n;
      }
      chosen.push(p); bnb(nr, chosen, bars + 1); chosen.pop();
    }
  }
  bnb(demArr, [], 0);
  return best;
}

function findRepeatPlans(pieces, stocks, blade, endLoss, kgm, yieldThreshold) {
  var cnt = {};
  pieces.forEach(function(p){cnt[p]=(cnt[p]||0)+1;});
  var items = Object.keys(cnt).map(Number).sort(function(a,b){return b-a;});
  var demArr = items.map(function(l){return cnt[l];});
  if (!items.length) return [];
  var allPats = enumAllPatterns(stocks, items, demArr, blade, endLoss);
  if (!allPats.length) return [];
  function maxRep(p) {
    var mr = Infinity;
    items.forEach(function(l,i){
      var n=0; for(var k=0;k<p.pat.length;k++) if(p.pat[k]===l) n++;
      if(n>0) mr = Math.min(mr, Math.floor(demArr[i]/n));
    });
    return isFinite(mr) ? mr : 0;
  }
  var candidates = allPats.map(function(p){
    var mr = maxRep(p);
    return {pat:p, maxRep:mr, score:p.yld*mr};
  }).filter(function(c){
    return c.maxRep >= 2 && c.pat.yld >= yieldThreshold/100;
  }).sort(function(a,b){
    return b.score-a.score || b.maxRep-a.maxRep || b.pat.yld-a.pat.yld;
  });
  var results = [], seenPat = {}, deadline = Date.now() + 1500;
  candidates.slice(0, 30).forEach(function(cand) {
    if (Date.now() > deadline) return;
    var p = cand.pat;
    var key = p.sl + '|' + p.pat.join(',');
    if (seenPat[key]) return; seenPat[key] = true;
    var nr = demArr.slice(), ok = true;
    items.forEach(function(l,i){
      var n=0; for(var k=0;k<p.pat.length;k++) if(p.pat[k]===l) n++;
      nr[i] -= n * cand.maxRep; if(nr[i]<0) ok=false;
    });
    if (!ok) return;
    var remBest;
    if (nr.some(function(r){return r>0;})) {
      var remDem = items.map(function(l,i){return nr[i];});
      var remPats = enumAllPatterns(stocks, items, remDem, blade, endLoss);
      remBest = bnbSolve(nr, items, remPats, 800);
    } else {
      remBest = {sol:[], bars:0, piece:0};
    }
    if (!remBest.sol) return;
    var repBars = [];
    for(var i=0;i<cand.maxRep;i++) repBars.push({pat:p.pat.slice(), loss:p.loss, sl:p.sl});
    var allBars = repBars.concat(remBest.sol.map(function(c){return {pat:c.pat.slice(), loss:c.loss, sl:c.sl};}));
    var totalUsable = allBars.reduce(function(s,b){return s+b.sl;},0);
    var totalPiece  = allBars.reduce(function(s,b){return s+b.pat.reduce(function(a,x){return a+x;},0);},0);
    var yld = totalUsable>0 ? totalPiece/totalUsable*100 : 0;
    var mm = calcMetrics(allBars, p.sl, endLoss, kgm);
    mm.yieldPct = yld; mm.patYieldPct = p.yld*100;
    mm.lossRate = 100-yld;
    mm.barKg = allBars.reduce(function(s,b){return s+b.sl/1000*kgm;},0);
    mm.lossKg = allBars.reduce(function(s,b){return s+b.loss;},0)/1000*kgm;
    mm.barCount = allBars.length; mm.repeatCount = cand.maxRep;
    results.push({sl:p.sl, bars:allBars, repeat:cand.maxRep, yld:yld, patYld:p.yld*100, metrics:mm, pat:p.pat});
  });
  results.sort(function(a,b){ return b.repeat-a.repeat || b.patYld-a.patYld; });
  var seen2={};
  return results.filter(function(r){
    var k=r.sl+'|'+r.pat.join(',');
    if(seen2[k]) return false; seen2[k]=true; return true;
  });
}

function calcPatternA(pieces, stocks, blade, endLoss, kgm) {
  var results = findRepeatPlans(pieces, stocks, blade, endLoss, kgm, 90);
  if (!results.length) return null;
  var best = results[0];
  return { label:'A', name:'Pattern A', bars:best.bars, sl:best.sl, metrics:best.metrics };
}

function calcPatternB(pieces, stocks, blade, endLoss, kgm) {
  var res90 = findRepeatPlans(pieces, stocks, blade, endLoss, kgm, 90);
  var repeatA = res90.length ? res90[0].repeat : 0;
  var res80 = findRepeatPlans(pieces, stocks, blade, endLoss, kgm, 80);
  if (!res80.length) return null;
  var better = res80.filter(function(r){ return r.repeat > repeatA; });
  if (!better.length) return null;
  var plan80 = better[0];
  return { label:'B', name:'Pattern B', plan90:null,
    plan80:{ bars:plan80.bars, sl:plan80.sl, metrics:plan80.metrics } };
}

function calcPatternC(pieces, stocks, blade, endLoss, kgm) { return null; }

function dpBestPat(pieces, capacity, blade) {
  var cnt={};pieces.forEach(function(p){cnt[p]=(cnt[p]||0)+1;});
  var lens=Object.keys(cnt).map(Number).sort(function(a,b){return b-a;});
  if(!lens.length)return{pat:[],used:0,loss:capacity};
  var key=capacity+'|'+lens.map(function(l){return l+':'+cnt[l];}).join(',');
  if(_dpCache[key])return _dpCache[key];
  var cap=capacity+blade,dp=new Array(cap+1).fill(null);
  dp[0]={used:0,prev:-1,item:0};
  lens.forEach(function(len){
    var maxTake=cnt[len],w=len+blade;
    for(var k=0;k<maxTake;k++)
      for(var c=cap;c>=w;c--){var pv=dp[c-w];if(!pv)continue;var nu=pv.used+len;if(!dp[c]||nu>dp[c].used)dp[c]={used:nu,prev:c-w,item:len};}
  });
  var best={pat:[],used:0,loss:capacity};
  for(var c2=cap;c2>=0;c2--){
    if(!dp[c2]||dp[c2].used===0)continue;
    var items2=[],cur=c2;
    while(cur>0&&dp[cur]&&dp[cur].prev>=0){items2.push(dp[cur].item);cur=dp[cur].prev;}
    if(!items2.length)continue;
    var au=items2.reduce(function(s,p){return s+p;},0),as2=au+(items2.length-1)*blade;
    if(as2<=capacity&&au>best.used){best={pat:items2.sort(function(a,b){return b-a;}),used:au,loss:capacity-as2};break;}
  }
  _dpCache[key]=best;
  return best;
}

function packDP(piecesIn, eff, blade) {
  var remaining=piecesIn.slice().sort(function(a,b){return b-a;});
  var bars=[];
  while(remaining.length>0){
    var cnt2={};remaining.forEach(function(p){cnt2[p]=(cnt2[p]||0)+1;});
    var best;
    if(Object.keys(cnt2).length<=8){
      best=dpBestPat(remaining,eff,blade);
    }else{
      var space=eff,pat=[],unused=[];
      remaining.forEach(function(p){var add=p+(pat.length>0?blade:0);if(space-add>=0){space-=add;pat.push(p);}else unused.push(p);});
      best={pat:pat,used:pat.reduce(function(s,p){return s+p;},0),loss:space};
    }
    if(!best.pat.length)break;
    bars.push({pat:best.pat,loss:best.loss});
    var rem2=remaining.slice();
    best.pat.forEach(function(p){var ix=rem2.indexOf(p);if(ix>=0)rem2.splice(ix,1);});
    remaining=rem2;
  }
  return bars;
}

function calcBundlePlan(pieces, stocks, blade, endLoss, kgm) {
  var sorted = pieces.slice().sort(function(a,b){return b-a;});
  var needed = sorted.reduce(function(s,p,i){return s+p+(i>0?blade:0);},0);
  var best = null;
  stocks.forEach(function(s){
    var eff=s.sl-endLoss; if(eff<needed) return;
    var loss=eff-needed;
    if(!best||s.sl<best.sl) best={sl:s.sl,pat:sorted.slice(),loss:loss,lossPerBar:loss,
      cutCount:1+sorted.length,lossRate:s.sl>0?(loss/eff)*100:100,
      barKg:(s.sl/1000)*kgm,lossKg:(loss/1000)*kgm};
  });
  return best;
}

function calcChargeMin(pieces, stocks, blade, endLoss, kgm) {
  var cnt={};pieces.forEach(function(p){cnt[p]=(cnt[p]||0)+1;});
  var plans=[];
  stocks.forEach(function(s){
    var eff=s.sl-endLoss; if(eff<=0) return;
    for(var N=1;N<=pieces.length;N++){
      var perBar={};
      Object.keys(cnt).forEach(function(len){perBar[len]=Math.ceil(cnt[len]/N);});
      var flatPat=[];
      Object.keys(perBar).map(Number).sort(function(a,b){return b-a;}).forEach(function(len){
        for(var k=0;k<perBar[len];k++) flatPat.push(len);
      });
      var used=flatPat.reduce(function(s,p,i){return s+p+(i>0?blade:0);},0);
      if(used>eff) continue;
      var actualN=0;
      Object.keys(cnt).forEach(function(len){actualN=Math.max(actualN,Math.ceil(cnt[len]/perBar[len]));});
      var lossPerBar=eff-used,extraLoss=0;
      Object.keys(cnt).forEach(function(len){
        var excess=perBar[len]*actualN-cnt[len]; if(excess>0) extraLoss+=excess*Number(len);
      });
      var totalLoss=lossPerBar*actualN+extraLoss;
      var totalUsable=s.sl*actualN;
      plans.push({sl:s.sl,N:actualN,flatPat:flatPat,used:used,lossPerBar:lossPerBar,
        totalLoss:totalLoss,chargeCount:1+flatPat.length,
        lossKg:(totalLoss/1000)*kgm,barKg:(s.sl/1000)*kgm*actualN,
        lossRate:totalUsable>0?(totalLoss/totalUsable)*100:0});
      break;
    }
  });
  plans.sort(function(a,b){return a.chargeCount-b.chargeCount||a.totalLoss-b.totalLoss;});
  var seen={},top=[];
  plans.forEach(function(p){var k=p.sl+'x'+p.N; if(!seen[k]){seen[k]=true;top.push(p);}});
  return top.slice(0,4);
}

function runCalc() {
  showCalcLoadingOverlay();
  var btn = document.getElementById('runBtn');
  btn.innerHTML = '<span class="sp"></span> 計算中...';
  btn.disabled = true;
  if (typeof _lastRegisteredRemnantSignature !== 'undefined') _lastRegisteredRemnantSignature = '';
  savePiecesHistory();
  saveSettings();

  // 入力値をDOMから収集
  var blade   = parseInt(document.getElementById('blade').value) || 3;
  var endLoss = parseInt(document.getElementById('endloss').value) || 75;
  var kgm     = parseFloat(document.getElementById('kgm').value) || 0;
  var minValidLen = parseInt(document.getElementById('minRemnantLen') ? document.getElementById('minRemnantLen').value : 500) || 500;

  var stocks = [];
  STD.forEach(function(sl, i) {
    if (!document.getElementById('sc' + i).checked) return;
    var mv = parseInt(document.getElementById('sm' + i).value);
    stocks.push({ sl: sl, max: isNaN(mv) || mv < 1 ? Infinity : mv });
  });
  if (!stocks.length) { alert('在庫ありの定尺をチェックしてください'); btn.innerHTML = '計算を実行する <span class="arr">→</span>'; btn.disabled = false; hideCalcLoadingOverlay(); return; }
  // 定尺バッジ更新
  var sb = document.getElementById('stocksBadge');
  if (sb) sb.textContent = '対象定尺: ' + stocks.map(function(s){return s.sl.toLocaleString()+'mm';}).join(' / ');;
  // 端材優先切断：希望端材長さがある場合、その長さ+部材最大長さに合うストックを優先
  var tgt = getTargetEndmat();
  if (tgt.len > 0) {
    stocks = stocks.map(function(s) {
      // 希望端材が出るよう、各定尺の「有効活用長さ」を少し短く見せて誘導
      return Object.assign({}, s, { _targetEndmat: tgt.len });
    });
  }

  var pieces = [];
  var pieceZones = {};
  for (var i = 0; i < totalRows; i++) {
    var lEl = document.getElementById('pl' + i), qEl = document.getElementById('pq' + i);
    var zEl = document.getElementById('pz' + i);
    if (!lEl) continue;
    var l = parseInt(lEl.value), q = parseInt(qEl.value);
    if (l > 12000) {
      alert('部材長さは12,000mm以下で入力してください。');
      btn.innerHTML = '計算を実行する <span class="arr">→</span>';
      btn.disabled = false;
      hideCalcLoadingOverlay();
      return;
    }
    if (l > 0 && q > 0) {
      for (var k = 0; k < q; k++) pieces.push(l);
      if (zEl && zEl.value) pieceZones[l] = zEl.value;
    }
  }
  var remnants = getRemnants();
  if (!pieces.length && !remnants.length) { alert('部材または残材を入力してください'); btn.innerHTML = '計算を実行する <span class="arr">→</span>'; btn.disabled = false; return; }

  // 残材のみモード
  if (!pieces.length && remnants.length > 0) {
    var remOnlyBars = remnants.slice().sort(function(a,b){return b-a;}).map(function(rl){ return {pat:[],loss:rl,sl:rl}; });
    render([],[],[],endLoss,remOnlyBars,kgm,[],[],null,null,null,null,null,null);
    btn.innerHTML = '計算を実行する <span class="arr">→</span>'; btn.disabled = false; return;
  }

  // カラーマップ構築
  pieceColorMap = {};
  var uniqueLens = [];
  pieces.forEach(function(p){ if(uniqueLens.indexOf(p)<0) uniqueLens.push(p); });
  uniqueLens.sort(function(a,b){return b-a;});
  uniqueLens.forEach(function(ln,ci){ pieceColorMap[ln]=PIECE_COLORS[ci%PIECE_COLORS.length]; });

  // 前のWorkerを停止
  if (calcWorker) { calcWorker.terminate(); calcWorker = null; }

  // 4並列Worker（yield/patA/patB/patC を同時実行）
  try {
    var workerCode = atob(WORKER_B64);
    var blob = new Blob([workerCode], {type:'application/javascript'});
    var url = URL.createObjectURL(blob);

    var baseMsg = { blade:blade, endLoss:endLoss, kgm:kgm,
      stocks:stocks, pieces:pieces, remnants:remnants, minValidLen:minValidLen };

    var results = {};
    var workers = [];
    var modes = ['yield','patA','patB'];
    var doneCount = 0;

    function onAllDone() {
      workers.forEach(function(w){ w.terminate(); });
      workers = [];
      btn.innerHTML = '計算を実行する <span class="arr">→</span>';
      btn.disabled = false;

      var ry = results['yield'] || {};
      var patA = results['patA'] ? results['patA'].patA : null;
      var patB = results['patB'] ? results['patB'].patB : null;
      var patC = null;

      // 残材マージ
      var remBars = ry.remnantBars || [];
      if (remBars.length) {
        var minVL = minValidLen;
        function mergeRemnants(pat) {
          if (!pat || !pat.bars) return pat;
          var merged = remBars.concat(pat.bars);
          var sl = pat.sl || (merged[0] && merged[0].sl) || stocks[0].sl;
          return Object.assign({}, pat, { bars: merged });
        }
        if (patA) patA = mergeRemnants(patA);
        if (patB) { if(patB.plan90) patB.plan90=mergeRemnants(patB.plan90); if(patB.plan80) patB.plan80=mergeRemnants(patB.plan80); }
        if (patC) patC = mergeRemnants(patC);
      }

      render(ry.single||[],[],ry.chgPlans||[],endLoss,remBars,kgm,
        ry.allDP||[],ry.calcPieces||[],ry.bundlePlan||null,
        patA,patB,patC,ry.yieldCard1||null,null);

      // 計算結果を保持（印刷時に自動登録）
      _lastCalcResult = {allDP:ry.allDP, patA:patA, patB:patB, patC:patC};
      // 切断完了ボタン用にグローバル保存
      _lastAllDP = ry.allDP || [];
      _lastPatA = patA;
      _lastPatB = patB;
      if (typeof autoSyncResultRemnants === 'function') autoSyncResultRemnants(_lastCalcResult);

      // 「切断完了」ボタンを結果エリア上部に追加
      var rp = document.getElementById('result');
      var cutBtn = document.createElement('div');
      cutBtn.style.cssText = 'padding:8px 0 4px;';
      cutBtn.innerHTML = '<button onclick="showCutDoneModal(_lastAllDP,_lastPatA,_lastPatB,null)" ' +
        'style="width:100%;background:rgba(167,139,250,.15);border:1px solid var(--br);color:var(--br);border-radius:10px;padding:10px;font-size:12px;font-weight:700;cursor:pointer;letter-spacing:.05em">' +
        '✂ 切断完了 → 端材を在庫に登録する</button>';
      if (rp && rp.firstChild) rp.insertBefore(cutBtn, rp.firstChild);
      else if (rp) rp.appendChild(cutBtn);
    }

    modes.forEach(function(mode) {
      var w = new Worker(url);
      workers.push(w);
      w.onmessage = function(e) {
        if (e.data.ok) {
          results[e.data.mode] = e.data.result;
        } else {
          console.warn('Worker error in mode', e.data.mode, e.data.error);
          results[e.data.mode] = {};
        }
        doneCount++;
        if (doneCount === modes.length) onAllDone();
      };
      w.onerror = function(err) {
        console.warn('Worker onerror', mode, err.message);
        results[mode] = {};
        doneCount++;
        if (doneCount === modes.length) onAllDone();
      };
      w.postMessage(Object.assign({}, baseMsg, {mode: mode}));
    });

    URL.revokeObjectURL(url);
    calcWorker = workers[0]; // 参照保持（terminate用）

  } catch(e) {
    console.warn('Worker unavailable, falling back:', e);
    setTimeout(function() {
      try { doCalc(); } catch(err) { alert('計算エラー: ' + err.message); }
      btn.innerHTML = '計算を実行する <span class="arr">→</span>';
      btn.disabled = false;
      hideCalcLoadingOverlay();
    }, 30);
  }
}

function doCalc() {
  // ── 変数宣言（先頭まとめ・巻き上げ問題を防ぐ） ──
  var blade, endLoss, kgm, stocks, remnants, pieces, uniqueLens;
  var remnantResult, remainingPieces, calcPieces, calcStocks;
  var single, top3, chgPlans, dpSingle, dpCands, allDP;
  var yieldBest, yieldCard1, yieldCard2, bundlePlan;
  var patA, patB, patC;
  var i, k, lEl, qEl, l, q, mv;

  blade   = parseInt(document.getElementById('blade').value) || 3;
  endLoss = parseInt(document.getElementById('endloss').value) || 75;
  kgm     = parseFloat(document.getElementById('kgm').value) || 0;

  // 在庫定尺
  stocks = [];
  STD.forEach(function(sl, idx) {
    if (!document.getElementById('sc' + idx).checked) return;
    mv = parseInt(document.getElementById('sm' + idx).value);
    stocks.push({ sl: sl, max: isNaN(mv) || mv < 1 ? Infinity : mv });
  });
  if (!stocks.length) { alert('在庫ありの定尺をチェックしてください'); return; }

  // 残材取得
  remnants = getRemnants();

  // 部材展開
  pieces = [];
  for (i = 0; i < totalRows; i++) {
    lEl = document.getElementById('pl' + i);
    qEl = document.getElementById('pq' + i);
    if (!lEl) continue;
    l = parseInt(lEl.value);
    q = parseInt(qEl.value);
    if (l > 12000) { alert('部材長さは12,000mm以下で入力してください。'); return; }
    if (l > 0 && q > 0) { for (k = 0; k < q; k++) pieces.push(l); }
  }
  // 部材未入力でも残材だけで計算できる（残材がある場合はOK）
  if (!pieces.length && !remnants.length) { alert('部材または残材を入力してください'); return; }
  if (!pieces.length && remnants.length > 0) {
    // 残材のみモード：残材リストをそのまま切断図表示
    var remOnlyBars = remnants.slice().sort(function(a,b){return b-a;}).map(function(rl){
      return { pat: [], loss: rl, sl: rl };
    });
    render([], [], [], endLoss, remOnlyBars, kgm, [], [], null, null, null, null, null, null);
    return;
  }
  pieces.sort(function(a, b) { return b - a; });

  // 部材カラーマップ構築
  pieceColorMap = {};
  uniqueLens = [];
  pieces.forEach(function(p){ if (uniqueLens.indexOf(p) < 0) uniqueLens.push(p); });
  uniqueLens.sort(function(a,b){return b-a;});
  uniqueLens.forEach(function(ln, ci){ pieceColorMap[ln] = PIECE_COLORS[ci % PIECE_COLORS.length]; });

  // 残材優先処理
  remnantResult = { remaining: pieces, remnantBars: [] };
  if (remnants.length > 0) {
    remnantResult = packWithRemnants(pieces, remnants, stocks, blade, endLoss);
  }
  remainingPieces = remnantResult.remaining;

  // calcPieces / calcStocks の決定
  calcPieces = remainingPieces;
  calcStocks = (remnants.length > 0 && remainingPieces.length > 0)
    ? STD.map(function(sl){ return {sl:sl, max:Infinity}; })
    : stocks;

  // 残材で全部材消化済みの場合は定尺計算をスキップ
  if (calcPieces.length === 0) {
    render([], [], [], endLoss, remnantResult.remnantBars, kgm, [], pieces, null, null, null, null, null, null);
    return;
  }

  single = [];
  calcStocks.forEach(function(s) {
    var eff = s.sl - endLoss;
    if (eff <= 0) return;
    var bars = pack(calcPieces, eff, blade);
    if (bars.length > s.max) return;
    var loss = bars.reduce(function(acc, b) { return acc + b.loss; }, 0);
    var usable = s.sl * bars.length;
    var gMap = {};
    bars.forEach(function(b) {
      var key = b.pat.join(',');
      if (!gMap[key]) gMap[key] = b.pat;
    });
    var chg = Object.values(gMap).reduce(function(acc, pat) { return acc + 1 + pat.length; }, 0);
    single.push({
      sl: s.sl, bars: bars, loss: loss, max: s.max,
      yld: usable > 0 ? (1 - loss / usable) * 100 : 0,
      lossRate: usable > 0 ? (loss / usable) * 100 : 100,
      barKg: (s.sl / 1000) * kgm * bars.length,
      lossKg: (loss / 1000) * kgm,
      chg: chg
    });
  });
  single.sort(function(a, b) { return a.lossRate - b.lossRate; });

  top3 = []; // 組み合わせ最適化セクション廃止

    chgPlans = calcChargeMin(calcPieces, calcStocks, blade, endLoss, kgm);

  // ── 歩留まり最大化計算（BnB全パターン探索）──
  allDP = [];
  (function() {
    var cnt = {};
    calcPieces.forEach(function(p){ cnt[p]=(cnt[p]||0)+1; });
    var bnbItems = Object.keys(cnt).map(Number).sort(function(a,b){return b-a;});
    var bnbDem   = bnbItems.map(function(l){return cnt[l];});
    var bnbPats  = enumAllPatterns(calcStocks, bnbItems, bnbDem, blade, endLoss);
    var best = bnbSolve(bnbDem, bnbItems, bnbPats, 3000);
    if (best.sol) {
      var bars = best.sol.map(function(c){return {pat:c.pat.slice(), loss:c.loss, sl:c.sl};});
      var slCnt={};
      bars.forEach(function(b){slCnt[b.sl]=(slCnt[b.sl]||0)+1;});
      var desc = Object.keys(slCnt).map(Number).sort(function(a,b){return b-a;}).map(function(sl){
        return sl.toLocaleString()+'mm × '+slCnt[sl]+'本';
      }).join(' + ');
      var tu = bars.reduce(function(s,b){return s+b.sl;},0);
      var tp = bars.reduce(function(s,b){return s+b.pat.reduce(function(a,p){return a+p;},0);},0);
      var lossKgV = bars.reduce(function(s,b){return s+b.loss;},0)/1000*kgm;
      var barKgV  = tu/1000*kgm;
      var lr = tu>0?(1-tp/tu)*100:100;
      allDP.push({desc:desc,lossRate:lr,lossKg:lossKgV,barKg:barKgV,
        bars:bars,slA:bars[0]?bars[0].sl:calcStocks[0].sl,slB:null,
        bA:bars,bB:[],chg:0,type:'bnb'});
    }
    // DP単一定尺もフォールバックとして追加
    calcStocks.forEach(function(s){
      var eff=s.sl-endLoss; if(eff<=0) return;
      var bars=packDP(calcPieces.slice(),eff,blade); if(bars.length>s.max) return;
      bars.forEach(function(b){b.sl=s.sl;});
      var loss=bars.reduce(function(a,b){return a+b.loss;},0);
      var tl=s.sl*bars.length;
      var pl=bars.reduce(function(a,b){return a+b.pat.reduce(function(s,p){return s+p;},0);},0);
      var gm={};bars.forEach(function(b){var k=b.pat.join(',');if(!gm[k])gm[k]=b.pat;});
      var chg=Object.values(gm).reduce(function(a,p){return a+1+p.length;},0);
      allDP.push({desc:s.sl.toLocaleString()+'mm × '+bars.length+'本',
        lossRate:tl>0?(1-pl/tl)*100:100,
        lossKg:loss/1000*kgm,barKg:tl/1000*kgm,
        bars:bars,slA:s.sl,slB:null,bA:bars,bB:[],chg:chg,type:'single'});
    });
    allDP.sort(function(a,b){return a.lossRate-b.lossRate;});
  })();
  yieldCard1 = allDP.length ? allDP[0] : null;
  yieldCard2 = null;

  // ── 束ね切りプラン ──
  bundlePlan = calcBundlePlan(calcPieces, calcStocks, blade, endLoss, kgm);

  // ── 3パターン取り合い計算 ──
  // 部材数が多い場合は重い計算を制限
  var isHeavy = calcPieces.length > 30;
  patA = calcPatternA(calcPieces, calcStocks, blade, endLoss, kgm);
  patB = isHeavy ? null : calcPatternB(calcPieces, calcStocks, blade, endLoss, kgm);
  patC = calcPatternC(calcPieces, calcStocks, blade, endLoss, kgm);

  // 残材バーをパターン結果にマージ（残材がある場合）
  var remBars = remnantResult.remnantBars;
  if (remBars && remBars.length) {
    var minValidLen = parseInt(document.getElementById('minRemnantLen') && document.getElementById('minRemnantLen').value) || 0;
    function mergeRemnants(pat) {
      if (!pat || !pat.bars) return pat;
      var merged = remBars.concat(pat.bars);
      var sl = pat.sl || (merged[0] && merged[0].sl) || calcStocks[0].sl;
      var m2 = calcMetrics(merged, sl, endLoss, kgm, minValidLen);
      return Object.assign({}, pat, { bars: merged, metrics: m2 });
    }
    if (patA) patA = mergeRemnants(patA);
    if (patB) {
      if (patB.plan90) patB.plan90 = mergeRemnants(patB.plan90);
      if (patB.plan80) patB.plan80 = mergeRemnants(patB.plan80);
    }
    if (patC) patC = mergeRemnants(patC);
  }

  _lastCalcResult = {
    allDP: allDP,
    patA: patA,
    patB: patB,
    patC: patC,
    meta: {
      calcId: 'calc_' + Date.now(),
      spec: (document.getElementById('spec') || {}).value || '',
      kind: (typeof getCurrentKind === 'function' ? getCurrentKind() : (typeof curKind !== 'undefined' ? curKind : '')) || '',
      minRemnantLen: parseInt((document.getElementById('minRemnantLen') || {}).value, 10) || 500,
      blade: blade,
      endLoss: endLoss,
      job: typeof getJobInfo === 'function' ? getJobInfo() : {},
      stocks: (stocks || []).map(function(stock) { return { sl: stock.sl, max: stock.max }; })
    }
  };

  render(single, top3, chgPlans, endLoss, remnantResult.remnantBars, kgm, allDP, calcPieces, bundlePlan, patA, patB, patC, yieldCard1, yieldCard2);

  // グローバル変数に保存（印刷・切断完了ボタン用）
  _lastAllDP = allDP || [];
  _lastPatA = patA;
  _lastPatB = patB;
  if (typeof autoSyncResultRemnants === 'function') autoSyncResultRemnants(_lastCalcResult);
}

function scheduleCalcIdle(callback) {
  if (typeof requestIdleCallback === 'function') {
    requestIdleCallback(function() { callback(); }, { timeout: 250 });
  } else {
    setTimeout(callback, 0);
  }
}

function ensureCalcLoadingOverlay() {
  return null;
}

function showCalcLoadingOverlay() {
  return;
}

function hideCalcLoadingOverlay() {
  return;
}

function createCalcWorker() {
  var workerCode = atob(WORKER_B64);
  var blob = new Blob([workerCode], { type: 'application/javascript' });
  var url = URL.createObjectURL(blob);
  return {
    worker: new Worker(url),
    url: url
  };
}

function runWorkerMode(mode, baseMsg) {
  return new Promise(function(resolve) {
    var handle = createCalcWorker();
    handle.worker.onmessage = function(e) {
      handle.worker.terminate();
      URL.revokeObjectURL(handle.url);
      if (e.data && e.data.ok) resolve(e.data.result || {});
      else resolve({});
    };
    handle.worker.onerror = function() {
      handle.worker.terminate();
      URL.revokeObjectURL(handle.url);
      resolve({});
    };
    handle.worker.postMessage(Object.assign({}, baseMsg, { mode: mode }));
  });
}

function applyWorkerResults(results, stocks, minValidLen, endLoss, kgm) {
  var ry = results.yield || {};
  var patA = results.patA ? results.patA.patA : null;
  var patB = results.patB ? results.patB.patB : null;
  var patC = null;
  var remBars = ry.remnantBars || [];
  var meta = {
    calcId: 'calc_' + Date.now(),
    spec: (document.getElementById('spec') || {}).value || '',
    kind: (typeof getCurrentKind === 'function' ? getCurrentKind() : (typeof curKind !== 'undefined' ? curKind : '')) || '',
    minRemnantLen: minValidLen,
    blade: parseInt((document.getElementById('blade') || {}).value, 10) || 3,
    endLoss: endLoss,
    job: typeof getJobInfo === 'function' ? getJobInfo() : {},
    stocks: (stocks || []).map(function(stock) { return { sl: stock.sl, max: stock.max }; }),
    origPieces: (ry.origPieces || []).slice(),
    calcPieces: (ry.calcPieces || []).slice(),
    selectedInventoryRemnants: typeof getSelectedInventoryRemnantDetails === 'function'
      ? getSelectedInventoryRemnantDetails()
      : [],
    remnantBars: (remBars || []).map(function(bar) {
      return { pat: (bar.pat || []).slice(), loss: bar.loss || 0, sl: bar.sl || 0 };
    })
  };
  if (remBars.length) {
    function mergeRemnants(pat) {
      if (!pat || !pat.bars) return pat;
      var merged = remBars.concat(pat.bars);
      var sl = pat.sl || (merged[0] && merged[0].sl) || stocks[0].sl;
      return Object.assign({}, pat, { bars: merged, metrics: calcMetrics(merged, sl, endLoss, kgm, minValidLen) });
    }
    if (patA) patA = mergeRemnants(patA);
    if (patB) {
      if (patB.plan90) patB.plan90 = mergeRemnants(patB.plan90);
      if (patB.plan80) patB.plan80 = mergeRemnants(patB.plan80);
    }
  }
  _lastCalcResult = { allDP: ry.allDP, patA: patA, patB: patB, patC: patC, meta: meta };
  render(ry.single || [], [], ry.chgPlans || [], endLoss, remBars, kgm,
    ry.allDP || [], ry.calcPieces || [], ry.bundlePlan || null,
    patA, patB, patC, ry.yieldCard1 || null, null);
  _lastAllDP = ry.allDP || [];
  _lastPatA = patA;
  _lastPatB = patB;
  if (typeof autoSyncResultRemnants === 'function') autoSyncResultRemnants(_lastCalcResult);
  var rp = document.getElementById('result');
  var existing = document.getElementById('cutDoneBanner');
  if (existing) existing.remove();
  var cutBtn = document.createElement('div');
  cutBtn.id = 'cutDoneBanner';
  cutBtn.style.cssText = 'padding:8px 0 4px;';
  cutBtn.innerHTML = '<button onclick="showCutDoneModal(_lastAllDP,_lastPatA,_lastPatB,null)" style="width:100%;background:rgba(167,139,250,.15);border:1px solid var(--br);color:var(--br);border-radius:10px;padding:10px;font-size:12px;font-weight:700;cursor:pointer;letter-spacing:.05em">✂ 切断完了 → 端材を在庫に登録する</button>';
  if (rp && rp.firstChild) rp.insertBefore(cutBtn, rp.firstChild);
  else if (rp) rp.appendChild(cutBtn);
}

function runCalc() {
  showCalcLoadingOverlay();
  var btn = document.getElementById('runBtn');
  btn.innerHTML = '<span class="sp"></span> 計算中...';
  btn.disabled = true;
  if (typeof _lastRegisteredRemnantSignature !== 'undefined') _lastRegisteredRemnantSignature = '';
  savePiecesHistory();
  saveSettings();

  var blade = parseInt(document.getElementById('blade').value) || 3;
  var endLoss = parseInt(document.getElementById('endloss').value) || 75;
  var kgm = parseFloat(document.getElementById('kgm').value) || 0;
  var minValidLen = parseInt(document.getElementById('minRemnantLen') ? document.getElementById('minRemnantLen').value : 500) || 500;

  var stocks = [];
  STD.forEach(function(sl, idx) {
    if (!document.getElementById('sc' + idx).checked) return;
    var mv = parseInt(document.getElementById('sm' + idx).value);
    stocks.push({ sl: sl, max: isNaN(mv) || mv < 1 ? Infinity : mv });
  });
  if (!stocks.length) { alert('在庫ありの定尺をチェックしてください'); btn.innerHTML = '計算を実行する <span class="arr">→</span>'; btn.disabled = false; hideCalcLoadingOverlay(); return; }

  var sb = document.getElementById('stocksBadge');
  if (sb) sb.textContent = '対象定尺: ' + stocks.map(function(s) { return s.sl.toLocaleString() + 'mm'; }).join(' / ');

  var pieces = [];
  for (var i = 0; i < totalRows; i++) {
    var lEl = document.getElementById('pl' + i), qEl = document.getElementById('pq' + i);
    if (!lEl) continue;
    var l = parseInt(lEl.value), q = parseInt(qEl.value);
    if (l > 12000) { alert('部材長さは12,000mm以下で入力してください。'); btn.innerHTML = '計算を実行する <span class="arr">→</span>'; btn.disabled = false; hideCalcLoadingOverlay(); return; }
    if (l > 0 && q > 0) for (var k = 0; k < q; k++) pieces.push(l);
  }
  var remnants = getRemnants();
  if (!pieces.length && !remnants.length) { alert('部材または残材を入力してください'); btn.innerHTML = '計算を実行する <span class="arr">→</span>'; btn.disabled = false; hideCalcLoadingOverlay(); return; }
  if (!pieces.length && remnants.length > 0) {
    var remOnlyBars = remnants.slice().sort(function(a, b) { return b - a; }).map(function(rl) { return { pat: [], loss: rl, sl: rl }; });
    _lastCalcResult = {
      allDP: [],
      patA: null,
      patB: null,
      patC: null,
      meta: {
        calcId: 'calc_' + Date.now(),
        spec: (document.getElementById('spec') || {}).value || '',
        kind: (typeof getCurrentKind === 'function' ? getCurrentKind() : (typeof curKind !== 'undefined' ? curKind : '')) || '',
        minRemnantLen: minValidLen,
        blade: blade,
        endLoss: endLoss,
        job: typeof getJobInfo === 'function' ? getJobInfo() : {},
        stocks: (stocks || []).map(function(stock) { return { sl: stock.sl, max: stock.max }; }),
        origPieces: pieces.slice(),
        calcPieces: [],
        selectedInventoryRemnants: typeof getSelectedInventoryRemnantDetails === 'function'
          ? getSelectedInventoryRemnantDetails()
          : [],
        remnantBars: remOnlyBars.map(function(bar) {
          return { pat: (bar.pat || []).slice(), loss: bar.loss || 0, sl: bar.sl || 0 };
        })
      }
    };
    render([], [], [], endLoss, remOnlyBars, kgm, [], [], null, null, null, null, null, null);
    btn.innerHTML = '計算を実行する <span class="arr">→</span>';
    btn.disabled = false;
    hideCalcLoadingOverlay();
    return;
  }

  var baseMsg = { blade: blade, endLoss: endLoss, kgm: kgm, stocks: stocks, pieces: pieces, remnants: remnants, minValidLen: minValidLen };
  var results = {};
  runWorkerMode('yield', baseMsg).then(function(res) {
    results.yield = res || {};
    return new Promise(function(resolve) {
      scheduleCalcIdle(function() {
        runWorkerMode('patA', baseMsg).then(function(r) {
          results.patA = r || {};
          resolve();
        });
      });
    });
  }).then(function() {
    return new Promise(function(resolve) {
      scheduleCalcIdle(function() {
        runWorkerMode('patB', baseMsg).then(function(r) {
          results.patB = r || {};
          resolve();
        });
      });
    });
  }).then(function() {
    applyWorkerResults(results, stocks, minValidLen, endLoss, kgm);
    btn.innerHTML = '計算を実行する <span class="arr">→</span>';
    btn.disabled = false;
    hideCalcLoadingOverlay();
  }).catch(function(err) {
    console.warn('Worker sequential calc failed', err);
    try { doCalc(); } catch (fallbackErr) { alert('計算エラー: ' + fallbackErr.message); }
    btn.innerHTML = '計算を実行する <span class="arr">→</span>';
    btn.disabled = false;
    hideCalcLoadingOverlay();
  });
}
